#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-05-29

# Local pre-flight for the Visual-Style PR lint.
#
# Run this BEFORE `gh pr create` to catch emoji/dingbat violations locally
# instead of after a red CI round-trip. It calls the SAME engine the CI
# workflow does (bin/validate-visual-style.py), so a clean result here is a
# clean result in CI — no drift.
#
# Usage:
#   bin/check-pr-visual-style.sh --title "feat: ..." --body-file /tmp/body.md
#   bin/check-pr-visual-style.sh --title "feat: ..."          # title only
#   bin/check-pr-visual-style.sh --body-file /tmp/body.md     # body only
#
# Common trap it catches: U+2713 (✓) / U+2717 (✗) check marks in a PR body —
# use the white-check / red-X from the vocabulary instead.
#
# Exit: 0 = both clean, 1 = a violation was found, 2 = usage error.

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
VALIDATOR="$SCRIPT_DIR/validate-visual-style.py"

TITLE=""
HAVE_TITLE=0
BODY_FILE=""

while [ $# -gt 0 ]; do
  case "$1" in
    --title)
      TITLE="${2:-}"
      HAVE_TITLE=1
      shift 2
      ;;
    --body-file)
      BODY_FILE="${2:-}"
      shift 2
      ;;
    -h | --help)
      grep '^#' "${BASH_SOURCE[0]}" | sed 's/^# \{0,1\}//'
      exit 0
      ;;
    *)
      echo "Unknown argument: $1" >&2
      exit 2
      ;;
  esac
done

if [ "$HAVE_TITLE" = "0" ] && [ -z "$BODY_FILE" ]; then
  echo "Nothing to check — pass --title and/or --body-file." >&2
  exit 2
fi

rc=0

if [ "$HAVE_TITLE" = "1" ]; then
  if ! PR_TITLE="$TITLE" python3 "$VALIDATOR" --mode title --env PR_TITLE; then
    rc=1
  fi
fi

if [ -n "$BODY_FILE" ]; then
  if [ ! -f "$BODY_FILE" ]; then
    echo "Body file not found: $BODY_FILE" >&2
    exit 2
  fi
  if ! python3 "$VALIDATOR" --mode body "$BODY_FILE"; then
    rc=1
  fi
fi

if [ "$rc" = "0" ]; then
  echo "Visual-style pre-flight: clean — safe to open the PR."
fi
exit "$rc"
